const OpenAI = require('openai');

// Bedrock API configuration
const apiKey = process.env.OPENAI_API_KEY || 'bedrock-api-key-';
const baseURL = process.env.OPENAI_BASE_URL || 'https://bedrock-mantle.us-east-1.api.aws/v1';

const client = new OpenAI({
  apiKey: apiKey,
  baseURL: baseURL,
});

async function askClaude(prompt, context = "") {
  try {
    const response = await client.chat.completions.create({
      model: "qwen.qwen3-coder-480b-a35b-instruct",
      messages: [{
        role: "user",
        content: context ? `${context}\n\n${prompt}` : prompt
      }],
      max_tokens: 4096,
    });

    return response.choices[0].message.content;
  } catch (error) {
    console.error("Error calling Claude:", error.message);
    throw error;
  }
}

module.exports = { askClaude };
